resource_leak.diff:
diff --git a/leaky_resources.go b/leaky_resources.go
index 1111111..2222222 100644
--- a/leaky_resources.go
+++ b/leaky_resources.go
@@ -1,3 +1,24 @@
 package review
+
+func leakResources(ctx context.Context, db *sql.DB, url string, name string) error {
+	f, err := os.Open(name)
+	if err != nil {
+		return err
+	}
+	data, err := io.ReadAll(f)
+	if err != nil {
+		return err
+	}
+	_ = data
+	resp, err := http.Get(url)
+	if err != nil {
+		return err
+	}
+	body, err := io.ReadAll(resp.Body)
+	if err != nil {
+		return err
+	}
+	_ = body
+	rows, err := db.QueryContext(ctx, "select id from users")
+	if err != nil {
+		return err
+	}
+	for rows.Next() {}
+	return nil
+}
